// =======================
// READ INPUTS
// =======================

// Current workflows from n8n
const workflows = $input.all()
  .map(i => i.json)
  .filter(w => w && typeof w.id === 'string' && typeof w.name === 'string');

const indexData = JSON.parse($('Get Index File Content').first()?.json?.data || '{}');

// =======================
// PREPARE STATE
// =======================

const results = [];
const updatedIndex = { ...indexData };

// Track only REAL workflow IDs from index
const existingIds = new Set(Object.keys(indexData));

// =======================
// STEP 1: CREATE / EDIT / RENAME
// =======================

for (const workflow of workflows) {
  const id = workflow.id;
  const name = workflow.name || 'unnamed';
  const path = `workflows/${name}.json`;

  // -------- CREATE --------
  if (!indexData[id]) {
    updatedIndex[id] = { name, file_path: path };

    results.push({
      status: 'create',
      workflowId: id,
      name,
      path,
      data: workflow
    });

    continue;
  }

  // -------- RENAME --------
  if (indexData[id].name !== name) {
    // delete old file
    results.push({
      status: 'delete',
      workflowId: id,
      name: indexData[id].name,
      path: indexData[id].file_path
    });

    // create new file
    results.push({
      status: 'create',
      workflowId: id,
      name,
      path,
      data: workflow
    });

    updatedIndex[id] = { name, file_path: path };
    existingIds.delete(id);
    continue;
  }

  // -------- EDIT --------
  results.push({
    status: 'edit',
    workflowId: id,
    name,
    path: indexData[id].file_path,
    data: workflow
  });

  existingIds.delete(id);
}

// =======================
// STEP 2: DELETE REMOVED WORKFLOWS
// =======================

for (const id of existingIds) {
  results.push({
    status: 'delete',
    workflowId: id,
    name: indexData[id].name,
    path: indexData[id].file_path
  });

  delete updatedIndex[id];
}

// =======================
// STEP 3: INDEX UPDATE (ONLY IF CHANGED)
// =======================

if (JSON.stringify(indexData) !== JSON.stringify(updatedIndex)) {
  results.push({
    status: 'index',
    data: updatedIndex
  });
}

// =======================
// OUTPUT FOR N8N
// =======================

return results.map(r => ({ json: r }));

const normalize = (obj) =>
  JSON.stringify(obj, (_, value) =>
    value && typeof value === 'object' && !Array.isArray(value)
      ? Object.keys(value)
          .sort()
          .reduce((o, k) => {
            o[k] = value[k];
            return o;
          }, {})
      : value
  );

return $input.all()
  .filter(item =>
    normalize(item.json.githubData) !== normalize(item.json.data)
  )
  .map(item => {
    const { githubData, ...rest } = item.json;
    return { json: rest };
  });
